   [FormControlEventHandler(formControlStr(EcoResCategory, EcoResCategory_CategoryProcurementManager), FormControlEventType::Lookup)]
   public static void EcoResCategory_CategoryProcurementManager_OnLookup(FormControl sender, FormControlEventArgs e)
   {
       FormRun formRun = sender.formRun();
       formRun.procurementCategoryManager_OnLookup(sender);

       FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
       cancelableArgs.CancelSuperCall();
   }

   public void procurementCategoryManager_OnLookup(FormControl _formControl)
   {
       Query           query           = new Query();
       SysTableLookup  sysTableLookup  = SysTableLookup::newParameters(tableNum(UBSDirPersonUserHcmWorker), _formControl);

       sysTableLookup.addLookupfield(fieldNum(UBSDirPersonUserHcmWorker,User));

       QueryBuildDataSource queryBuildDataSource = query.addDataSource(tableNum(UBSDirPersonUserHcmWorker));
       queryBuildDataSource.addSortField(fieldNum(UBSDirPersonUserHcmWorker,User),SortOrder::Ascending);

       sysTableLookup.parmQuery(query);
       sysTableLookup.performFormLookup();
   }
